ylabel('Magnitude (dB)'); xlabel('Normalized Frequency (\times\pi rad/sample)');
subplot(2,1,2); plot(w/pi, phase_h); title('Phase');
ylabel('Phase (rad)'); xlabel('Normalized Frequency (\times\pi rad/sample)');
